import React, { useState, useEffect, useContext } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { ThemeContext } from '../../context/ThemeContext';

const Navbar = ({ isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const location = useLocation();
    const { theme, toggleTheme } = useContext(ThemeContext);
    const [hoveredMenu, setHoveredMenu] = useState(null);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [logoHovered, setLogoHovered] = useState(false);

    const isDark = theme === 'dark';

    // Handle scroll effect
    useEffect(() => {
        const handleScroll = () => {
            setScrolled(window.scrollY > 50);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    const navigateTo = (path) => {
        navigate(path);
        setMobileMenuOpen(false);
    };

    const getMenuStyle = (menuPath) => ({
        background: 'none', 
        border: 'none',
        color: hoveredMenu === menuPath || location.pathname === menuPath ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
        fontWeight: '700', 
        cursor: 'pointer', 
        fontSize: '14px', 
        transition: 'all 0.3s ease',
        padding: '8px 0',
        position: 'relative',
        letterSpacing: '0.3px'
    });

    return (
        <>
            <nav style={{ 
                display: 'flex', 
                justifyContent: 'space-between', 
                alignItems: 'center', 
                padding: scrolled ? '15px 5%' : '20px 5%', 
                background: scrolled 
                    ? (isDark ? 'rgba(12, 10, 9, 0.95)' : 'rgba(245, 245, 244, 0.95)')
                    : (isDark ? '#0c0a09' : '#f5f5f4'), 
                borderBottom: `1px solid ${isDark ? '#262626' : '#e5e5e5'}`,
                position: 'sticky',
                top: 0,
                zIndex: 1000,
                transition: 'all 0.3s ease',
                backdropFilter: scrolled ? 'blur(10px)' : 'none'
            }}>
                <div 
                    onClick={() => navigateTo('/')} 
                    style={{ 
                        cursor: 'pointer',
                        transition: 'all 0.3s ease',
                        position: 'relative'
                    }}
                    onMouseEnter={(e) => {
                        setLogoHovered(true);
                        e.currentTarget.style.transform = 'scale(1.02)';
                    }}
                    onMouseLeave={(e) => {
                        setLogoHovered(false);
                        e.currentTarget.style.transform = 'scale(1)';
                    }}
                >
                    {/* Logo dengan efek gradient dan animasi */}
                    <div style={{ position: 'relative', display: 'inline-block' }}>
                        <h2 style={{ 
                            margin: 0, 
                            fontSize: 'clamp(18px, 4vw, 22px)',
                            fontWeight: '800',
                            letterSpacing: '-0.5px',
                            position: 'relative',
                            display: 'flex',
                            alignItems: 'center',
                            gap: '2px',
                            flexWrap: 'wrap'
                        }}>
                            <span style={{ 
                                color: isDark ? '#fef3c7' : '#1c1917',
                                transition: 'all 0.3s ease',
                                textShadow: logoHovered ? (isDark ? '0 0 10px rgba(234,88,12,0.3)' : '0 0 10px rgba(234,88,12,0.2)') : 'none'
                            }}>
                                Pasukan
                            </span>
                            <span style={{ 
                                color: '#ea580c',
                                position: 'relative',
                                display: 'inline-block',
                                transition: 'all 0.3s ease',
                                transform: logoHovered ? 'translateY(-2px)' : 'translateY(0)',
                                textShadow: logoHovered ? '0 0 8px rgba(234,88,12,0.5)' : 'none'
                            }}>
                                Yerus
                                {/* Decorative dot di atas huruf Y */}
                                <span style={{
                                    position: 'absolute',
                                    top: '-8px',
                                    right: '-4px',
                                    width: '6px',
                                    height: '6px',
                                    background: '#ea580c',
                                    borderRadius: '50%',
                                    opacity: logoHovered ? 1 : 0.5,
                                    transition: 'all 0.3s ease',
                                    transform: logoHovered ? 'scale(1.2)' : 'scale(1)'
                                }} />
                            </span>
                            <span style={{ 
                                color: isDark ? '#fef3c7' : '#1c1917',
                                transition: 'all 0.3s ease'
                            }}>
                                Solo
                            </span>
                        </h2>

                        {/* Underline animation */}
                        <div style={{
                            position: 'absolute',
                            bottom: '-4px',
                            left: '0',
                            width: logoHovered ? '100%' : '0%',
                            height: '2px',
                            background: 'linear-gradient(90deg, #ea580c, #f59e0b)',
                            borderRadius: '2px',
                            transition: 'width 0.3s ease'
                        }} />
                    </div>

                    {/* Badge kecil untuk menunjukkan status */}
                    <div style={{
                        position: 'absolute',
                        top: '-8px',
                        right: '-20px',
                        fontSize: '10px',
                        background: 'linear-gradient(135deg, #ea580c, #f59e0b)',
                        color: '#fff',
                        padding: '2px 6px',
                        borderRadius: '20px',
                        fontWeight: '700',
                        opacity: scrolled ? 0 : 1,
                        transform: scrolled ? 'translateX(10px)' : 'translateX(0)',
                        transition: 'all 0.3s ease',
                        pointerEvents: 'none',
                        whiteSpace: 'nowrap'
                    }}>
                        {isAuthenticated ? '✓' : '⚡'}
                    </div>
                </div>

                {/* Desktop Menu */}
                <div className="nav-menu" style={{ display: 'flex', gap: '30px', alignItems: 'center' }}>
                    <button 
                        style={getMenuStyle('/')} 
                        onClick={() => navigateTo('/')} 
                        onMouseEnter={() => setHoveredMenu('/')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Beranda
                        {location.pathname === '/' && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>
                    <button 
                        style={getMenuStyle('/eksplorasi')} 
                        onClick={() => navigateTo('/eksplorasi')} 
                        onMouseEnter={() => setHoveredMenu('/eksplorasi')} 
                        onMouseLeave={() => setHoveredMenu(null)}
                    >
                        Lowongan
                        {location.pathname === '/eksplorasi' && (
                            <span style={{
                                position: 'absolute',
                                bottom: '0',
                                left: '0',
                                width: '100%',
                                height: '2px',
                                background: '#ea580c',
                                borderRadius: '2px'
                            }} />
                        )}
                    </button>

                    {/* Menu hanya muncul untuk akun dengan role Perusahaan */}
                    {isAuthenticated && userRole === 'Perusahaan' && (
                        <>
                            <button 
                                onClick={() => navigateTo('/hrd/dashboard')}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: hoveredMenu === '/hrd/dashboard' ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                    fontWeight: '700',
                                    cursor: 'pointer',
                                    fontSize: '14px',
                                    transition: 'all 0.3s ease',
                                    padding: '8px 0'
                                }}
                                onMouseEnter={() => setHoveredMenu('/hrd/dashboard')}
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Dashboard
                            </button>
                            <button 
                                onClick={() => navigateTo('/hrd/branding')}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: hoveredMenu === '/hrd/branding' ? '#ea580c' : (isDark ? '#fff' : '#1c1917'),
                                    fontWeight: '700',
                                    cursor: 'pointer',
                                    fontSize: '14px',
                                    transition: 'all 0.3s ease',
                                    padding: '8px 0'
                                }}
                                onMouseEnter={() => setHoveredMenu('/hrd/branding')}
                                onMouseLeave={() => setHoveredMenu(null)}
                            >
                                Branding
                            </button>
                        </>
                    )}
                </div>

                <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                    {/* Theme Toggle Button */}
                    <button
                        onClick={toggleTheme}
                        style={{
                            background: isDark ? '#1c1917' : '#e5e5e5',
                            border: `1px solid ${isDark ? '#262626' : '#d4d4d4'}`,
                            borderRadius: '50%',
                            width: '40px',
                            height: '40px',
                            cursor: 'pointer',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            transition: 'all 0.3s ease',
                            fontSize: '18px'
                        }}
                        onMouseEnter={(e) => {
                            e.currentTarget.style.transform = 'scale(1.1)';
                            e.currentTarget.style.boxShadow = '0 2px 10px rgba(0,0,0,0.2)';
                        }}
                        onMouseLeave={(e) => {
                            e.currentTarget.style.transform = 'scale(1)';
                            e.currentTarget.style.boxShadow = 'none';
                        }}
                    >
                        {isDark ? '☀️' : '🌙'}
                    </button>

                    {isAuthenticated ? (
                        <button 
                            onClick={handleLogout} 
                            style={{ 
                                padding: '8px 20px', 
                                borderRadius: '30px', 
                                border: '1px solid #ef4444', 
                                color: '#ef4444', 
                                cursor: 'pointer', 
                                background: 'transparent',
                                fontWeight: '600',
                                fontSize: '13px',
                                transition: 'all 0.3s ease'
                            }}
                            onMouseEnter={(e) => {
                                e.currentTarget.style.background = '#ef4444';
                                e.currentTarget.style.color = '#fff';
                                e.currentTarget.style.transform = 'translateY(-2px)';
                            }}
                            onMouseLeave={(e) => {
                                e.currentTarget.style.background = 'transparent';
                                e.currentTarget.style.color = '#ef4444';
                                e.currentTarget.style.transform = 'translateY(0)';
                            }}
                        >
                            Keluar
                        </button>
                    ) : (
                        <button 
                            onClick={() => navigateTo('/login')} 
                            style={{ 
                                padding: '8px 24px', 
                                borderRadius: '30px', 
                                border: '1px solid #ea580c', 
                                background: hoveredMenu === '/login' ? '#ea580c' : 'transparent', 
                                color: hoveredMenu === '/login' ? '#fff' : '#ea580c', 
                                fontWeight: '700', 
                                fontSize: '13px', 
                                cursor: 'pointer', 
                                transition: 'all 0.3s ease',
                                boxShadow: hoveredMenu === '/login' ? '0 4px 15px rgba(234,88,12,0.3)' : 'none'
                            }}
                            onMouseEnter={(e) => {
                                setHoveredMenu('/login');
                                e.currentTarget.style.transform = 'translateY(-2px)';
                            }}
                            onMouseLeave={(e) => {
                                setHoveredMenu(null);
                                e.currentTarget.style.transform = 'translateY(0)';
                            }}
                        >
                            Login
                        </button>
                    )}

                    {/* Mobile menu button */}
                    <button 
                        onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
                        style={{
                            display: 'none',
                            background: 'none',
                            border: 'none',
                            color: isDark ? '#fff' : '#1c1917',
                            fontSize: '24px',
                            cursor: 'pointer',
                            padding: '8px'
                        }}
                        className="mobile-menu-btn"
                    >
                        ☰
                    </button>
                </div>
            </nav>

            {/* Mobile Menu */}
            {mobileMenuOpen && (
                <div style={{
                    position: 'fixed',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    background: isDark ? '#0c0a09' : '#f5f5f4',
                    zIndex: 999,
                    padding: '80px 40px',
                    animation: 'slideIn 0.3s ease'
                }}>
                    <button 
                        onClick={() => setMobileMenuOpen(false)}
                        style={{
                            position: 'absolute',
                            top: '20px',
                            right: '20px',
                            background: 'none',
                            border: 'none',
                            color: isDark ? '#fff' : '#1c1917',
                            fontSize: '30px',
                            cursor: 'pointer'
                        }}
                    >
                        ✕
                    </button>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '30px', alignItems: 'center' }}>
                        <button onClick={() => navigateTo('/')} style={getMenuStyle('/')}>Beranda</button>
                        <button onClick={() => navigateTo('/eksplorasi')} style={getMenuStyle('/eksplorasi')}>Lowongan</button>
                        {isAuthenticated && userRole === 'Perusahaan' && (
                            <>
                                <button onClick={() => navigateTo('/hrd/dashboard')} style={{ color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '18px' }}>Dashboard</button>
                                <button onClick={() => navigateTo('/hrd/branding')} style={{ color: isDark ? '#fff' : '#1c1917', background: 'none', border: 'none', fontSize: '18px' }}>Branding</button>
                            </>
                        )}
                        {isAuthenticated ? (
                            <button onClick={handleLogout} style={{ padding: '10px 30px', borderRadius: '30px', border: '1px solid #ef4444', color: '#ef4444', background: 'transparent' }}>Keluar</button>
                        ) : (
                            <button onClick={() => navigateTo('/login')} style={{ padding: '10px 30px', borderRadius: '30px', background: '#ea580c', color: '#fff', border: 'none' }}>Login</button>
                        )}
                    </div>
                </div>
            )}

            <style>{`
                @keyframes slideIn {
                    from {
                        transform: translateX(100%);
                    }
                    to {
                        transform: translateX(0);
                    }
                }
                @media (max-width: 768px) {
                    .nav-menu {
                        display: none !important;
                    }
                    .mobile-menu-btn {
                        display: block !important;
                    }
                }
            `}</style>
        </>
    );
};

export default Navbar;
